                  <div style={s.cardTop}>
                    <div style={s.logoBox(c.bg, c.text)}>{initials(job.company)}</div>
                    <div><div style={s.jobTitle}>{job.title}</div><div style={s.jobSub}>{job.company} · {job.location}</div></div>
                    <span style={s.badge("#FAEEDA", "#854F0B")}>{job.salary}</span>
                  </div>
                </div>
              );
            })
          )}
        </div>
      )}

      {/* Staff & Attendance */}
      {page === "employer" && (() => {
        const now = new Date();
        const year = now.getFullYear();
        const month = now.getMonth();
        const daysInMonth = new Date(year, month + 1, 0).getDate();
        const monthName = now.toLocaleDateString(language === "hi" ? "hi-IN" : "en-IN", { month: "long", year: "numeric" });

        return (
          <div style={s.empLayout}>
            <div style={s.empList}>
              <div style={s.empAddBox}>
                <label style={s.formLabel}>{t.employeeName}</label>
                <input style={{ ...s.formInput, marginBottom: 8 }} placeholder="e.g. Ramesh Kumar" value={empForm.name} onChange={(e) => setEmpForm({ ...empForm, name: e.target.value })} />
                <label style={s.formLabel}>{t.employeeRole}</label>
                <input style={{ ...s.formInput, marginBottom: 8 }} placeholder="e.g. Driver, Mistri" value={empForm.role} onChange={(e) => setEmpForm({ ...empForm, role: e.target.value })} />
                <label style={s.formLabel}>{t.wageType}</label>
                <select style={{ ...s.formInput, marginBottom: 8 }} value={empForm.wageType} onChange={(e) => setEmpForm({ ...empForm, wageType: e.target.value })}>
                  <option value="daily">{t.dailyWageOpt}</option>
                  <option value="monthly">{t.monthlyWageOpt}</option>
                </select>
                <label style={s.formLabel}>{t.wageAmount}</label>
                <input type="number" style={{ ...s.formInput, marginBottom: 8 }} placeholder="e.g. 500" value={empForm.wageAmount} onChange={(e) => setEmpForm({ ...empForm, wageAmount: e.target.value })} />
                <button style={s.submitBtn} onClick={handleAddEmployee}>{t.addBtn}</button>
              </div>

              {employees.length === 0 && <p style={{ color: "#aaa", textAlign: "center", marginTop: "1rem", fontSize: 13 }}>{t.noEmployees}</p>}
              {employees.map((emp, i) => {
                const c = colors[i % colors.length];
                const stats = monthStats(emp, year, month);
                return (
                  <div key={emp.id} style={s.empCard(selectedEmployee?.id === emp.id)} onClick={() => setSelectedEmployee(emp)}>
                    <div style={s.cardTop}>
                      <div style={s.empAvatar(c.bg, c.text)}>{initials(emp.name)}</div>
                      <div style={{ flex: 1 }}>
                        <div style={s.jobTitle}>{emp.name}</div>
                        <div style={s.jobSub}>{emp.role}</div>
                      </div>
                    </div>
                    <div style={s.badgeRow}>
                      <span style={s.badge("#D9F0E0", "#1B7A43")}>{stats.present} {t.daysPresent}</span>
                      <span style={s.badge("#FBE6D4", "#A35A0B")}>{stats.leave} {t.daysLeave}</span>
                    </div>
                  </div>
                );
              })}
            </div>

            <div style={s.empDetail}>
              {!selectedEmployee ? (
                <div style={s.empty}>
                  <span style={{ fontSize: 48 }}>🧑‍🔧</span>
                  <p>{t.selectEmployeeMsg}</p>
                </div>
              ) : (() => {
                const emp = employees.find((e) => e.id === selectedEmployee.id) || selectedEmployee;
                const stats = monthStats(emp, year, month);
                return (
                  <>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "1rem", gap: 8 }}>
                      <div>
                        <div style={s.detailTitle}>{emp.name}</div>
                        <div style={s.detailSub}>{emp.role} · {emp.wageType === "daily" ? `₹${emp.wageAmount}${t.perDay}` : `₹${emp.wageAmount}${t.perMonth}`}</div>
                      </div>
                      <button style={s.removeLink} onClick={() => removeEmployee(emp.id)}>{t.removeWorker}</button>
                    </div>

                    <div style={s.statRow}>
                      <div style={s.statBox("#E6F1FB", "#185FA5")}>
                        <div style={s.statNum}>{stats.present}</div>
                        <div style={s.statLabel}>{t.daysPresent}</div>
                      </div>
                      <div style={s.statBox("#FBE6D4", "#A35A0B")}>
                        <div style={s.statNum}>{stats.leave}</div>
                        <div style={s.statLabel}>{t.daysLeave}</div>
                      </div>
                      <div style={s.statBox("#EAF3DE", "#3B6D11")}>
                        <div style={s.statNum}>₹{stats.salary}</div>
                        <div style={s.statLabel}>{t.estSalary}</div>
                      </div>
                    </div>

                    <div style={s.section}>
                      <div style={s.sectionTitle}>{t.thisMonth} — {monthName}</div>
                      <p style={{ fontSize: 13, color: "#888", marginTop: 6, marginBottom: 0 }}>{t.tapToMark}</p>
                      <div style={s.calGrid}>
                        {Array.from({ length: daysInMonth }, (_, i) => i + 1).map((day) => {
                          const key = dateKey(year, month, day);
                          const status = emp.attendance[key];
                          return (
                            <div key={day} style={s.calCell(status)} onClick={() => cycleAttendance(emp.id, key)}>
                              {day}
                            </div>
                          );
                        })}
                      </div>
                      <div style={s.legendRow}>
                        <span><span style={s.legendDot("#1B7A43")}></span>{t.legendPresent}</span>
                        <span><span style={s.legendDot("#A35A0B")}></span>{t.legendLeave}</span>
                        <span><span style={s.legendDot("#ccc")}></span>{t.legendUnmarked}</span>
                      </div>
                    </div>
                  </>
                );
              })()}
            </div>
          </div>
        );
      })()}

      {/* Post Job */}
      {page === "post" && (
        <div style={s.page}>
          <h2 style={{ fontSize: 22, fontWeight: 700, marginBottom: "1.2rem" }}>{t.postTitle}</h2>
          <div style={s.formGrid}>
            <div><label style={s.formLabel}>{t.jobTitle}</label>
              <input style={s.formInput} placeholder="e.g. Driver, Mistri, Teacher" value={postForm.title} onChange={(e) => setPostForm({ ...postForm, title: e.target.value })} /></div>
            <div><label style={s.formLabel}>{t.companyName}</label>
              <input style={s.formInput} placeholder="e.g. Ramesh Ji ka Kaam" value={postForm.company} onChange={(e) => setPostForm({ ...postForm, company: e.target.value })} /></div>
          </div>
          <div style={s.formGrid}>
            <div><label style={s.formLabel}>{t.jobLocation}</label>
              <input style={s.formInput} placeholder="e.g. Neemuch, Mandsaur" value={postForm.location} onChange={(e) => setPostForm({ ...postForm, location: e.target.value })} /></div>
            <div><label style={s.formLabel}>{t.jobSalary}</label>
              <input style={s.formInput} placeholder="e.g. ₹500/day or ₹10,000/month" value={postForm.salary} onChange={(e) => setPostForm({ ...postForm, salary: e.target.value })} /></div>
          </div>
          <div style={s.formGrid}>
            <div><label style={s.formLabel}>{t.jobType}</label>
              <select style={s.formInput} value={postForm.type} onChange={(e) => setPostForm({ ...postForm, type: e.target.value })}>
                <option value="Full-time">{t.fullTime}</option>
                <option value="Part-time">{t.partTime}</option>
                <option value="Daily Wage">{t.dailyWage}</option>
                <option value="Internship">{t.internship}</option>
              </select></div>
            <div><label style={s.formLabel}>{t.jobDomain}</label>
              <select style={s.formInput} value={postForm.domain} onChange={(e) => setPostForm({ ...postForm, domain: e.target.value })}>
                <option>Farming</option>
                <option>Construction</option>
                <option>Teaching</option>
                <option>Healthcare</option>
                <option>Transport</option>
                <option>Skilled Work</option>
                <option>Government</option>
                <option>Technical</option>
                <option>Engineering</option>
                <option>Other</option>
              </select></div>
          </div>
          <label style={s.formLabel}>{t.jobDesc}</label>
          <textarea style={{ ...s.formInput, minHeight: 100, resize: "vertical" }}
            placeholder="Kaam ke baare mein batayen / काम के बारे में बताएं..." value={postForm.desc} onChange={(e) => setPostForm({ ...postForm, desc: e.target.value })} />
          <button style={s.submitBtn} onClick={handlePost}>{t.publish}</button>

          <div style={{ marginTop: "2.5rem", paddingTop: "1.5rem", borderTop: "1px solid #eee" }}>
            <h2 style={{ fontSize: 18, fontWeight: 700, marginBottom: "1rem" }}>{t.yourPostedJobs}</h2>
            {postedJobs.length === 0 ? (
              <p style={{ color: "#aaa", fontSize: 14 }}>{t.noPostedJobsYet}</p>
            ) : (
              postedJobs.map((job) => {
                const apps = applications.filter((a) => a.jobId === job.id);
                const expanded = expandedJobId === job.id;
                return (
                  <div key={job.id} style={s.postedJobCard}>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", gap: 8 }}>
                      <div>
                        <div style={s.jobTitle}>{job.title}</div>
                        <div style={s.jobSub}>{job.company} · {job.location}</div>
                      </div>
                      <button style={s.chip(expanded)} onClick={() => setExpandedJobId(expanded ? null : job.id)}>
                        {apps.length} {t.applicantsLabel} {expanded ? "▲" : "▼"}
                      </button>
                    </div>
                    {expanded && (
                      <div style={{ marginTop: 10, borderTop: "1px solid #f0f0f0", paddingTop: 10 }}>
                        {apps.length === 0 ? (
                          <p style={{ fontSize: 13, color: "#aaa" }}>{t.noApplicants}</p>
                        ) : (
                          apps.map((a) => (
                            <div key={a.id} style={s.applicantCard}>
                              <div style={{ display: "flex", justifyContent: "space-between", gap: 8 }}>
                                <strong style={{ fontSize: 14 }}>{a.name}</strong>
                                <span style={{ fontSize: 12, color: "#888", whiteSpace: "nowrap" }}>{t.appliedOn} {a.appliedAt}</span>
                              </div>
                              {a.message && <p style={{ fontSize: 13, color: "#555", margin: "4px 0" }}>{a.message}</p>}
                              <div style={{ display: "flex", gap: 10, marginTop: 6, alignItems: "center", flexWrap: "wrap" }}>
                                <a href={`tel:${a.phone}`} style={{ fontSize: 13, color: "#185FA5", textDecoration: "none", fontWeight: 600 }}>📞 {a.phone}</a>
                                <button style={s.hireBtn(a.status === "hired")} onClick={() => toggleHired(a.id)}>
                                  {a.status === "hired" ? t.hired : t.markHired}
                                </button>
                              </div>
                            </div>
                          ))
                        )}
                      </div>
                    )}
                  </div>
                );
              })
            )}
          </div>
        </div>
      )}

      {/* Apply Modal */}
      {applyingJob && (
        <div style={s.modalOverlay} onClick={() => setApplyingJob(null)}>
          <div style={s.modalBox} onClick={(e) => e.stopPropagation()}>
            <h3 style={{ fontSize: 18, fontWeight: 700, marginBottom: 2 }}>{t.applyFormTitle}</h3>
            <p style={{ fontSize: 13, color: "#666", marginBottom: 14 }}>{applyingJob.title} · {applyingJob.company}</p>
            <label style={s.formLabel}>{t.yourName}</label>
            <input style={s.formInput} placeholder="e.g. Suresh Patel" value={applyForm.name} onChange={(e) => setApplyForm({ ...applyForm, name: e.target.value })} />
            <label style={s.formLabel}>{t.yourPhone}</label>
            <input style={s.formInput} type="tel" placeholder="e.g. 98765 43210" value={applyForm.phone} onChange={(e) => setApplyForm({ ...applyForm, phone: e.target.value })} />
            <label style={s.formLabel}>{t.yourMessage}</label>
            <textarea style={{ ...s.formInput, minHeight: 70, resize: "vertical" }} value={applyForm.message} onChange={(e) => setApplyForm({ ...applyForm, message: e.target.value })} />
            <div style={{ display: "flex", gap: 8 }}>
              <button style={{ ...s.saveBtn(false), flex: 1 }} onClick={() => setApplyingJob(null)}>{t.cancel}</button>
              <button style={{ ...s.submitBtn, flex: 1, marginTop: 0 }} onClick={submitApplication}>{t.submitApplication}</button>
            </div>
          </div>
        </div>
      )}

      <div style={s.toast}>{toast}</div>
    </div>
  );
}
